code://company/recollection/test/sync-cli-single-instance.test.ts::collectOutput | function | async function collectOutput(child: ReturnType<typeof spawn>): Promise<RunResult> {
  let stdout = '';
  let stderr = '';
  child.stdout!.on('data', d => { stdout += d.toString(); });
  child.stderr!.on('data', d => { stderr += d.toString(); });
  const status: number | null = await new Promise(resolve => {
    child.on('close', code => resolve(code));
  });
  return { status, stdout, stderr };
}
